import React, { useState } from 'react';
import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Link,
  Alert,
  CircularProgress,
  Container,
  InputAdornment,
  IconButton
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  Email,
  Lock,
  Instagram,
  YouTube,
  Telegram as TelegramIcon
} from '@mui/icons-material';
import { Link as RouterLink } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../../contexts/AuthContext';

const Login = () => {
  const { login } = useAuth();
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      await login(formData.email, formData.password);
      toast.success('Login realizado com sucesso!');
    } catch (error) {
      const errorMessage = error.response?.data?.message || 'Erro ao fazer login. Verifique suas credenciais.';
      setError(errorMessage);
      toast.error(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
  };

  // Dados de mercado simulados para animação
  const cryptoSymbols = ['₿', 'Ξ', '◇', '⟐', '$'];
  const marketData = ['$67,234', '$3,421', '$156.78', '$0.52', '+12.5%', '-3.2%', '+8.7%'];

  return (
    <Box
      sx={{
        minHeight: '100vh',
        position: 'relative',
        overflow: 'hidden',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 2,
        background: 'linear-gradient(135deg, #0a0e1a 0%, #1a1f2e 50%, #0a0e1a 100%)',
        '&::before': {
          content: '""',
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundImage: `
            repeating-linear-gradient(
              90deg,
              transparent,
              transparent 98px,
              rgba(0, 255, 100, 0.03) 100px,
              rgba(0, 255, 100, 0.03) 102px
            ),
            repeating-linear-gradient(
              0deg,
              transparent,
              transparent 98px,
              rgba(0, 255, 100, 0.03) 100px,
              rgba(0, 255, 100, 0.03) 102px
            )
          `,
          animation: 'gridMove 20s linear infinite',
          pointerEvents: 'none'
        },
        '@keyframes gridMove': {
          '0%': { transform: 'translate(0, 0)' },
          '100%': { transform: 'translate(100px, 100px)' }
        },
        '@keyframes float': {
          '0%, 100%': { transform: 'translateY(0px) rotate(0deg)', opacity: 0.6 },
          '50%': { transform: 'translateY(-20px) rotate(180deg)', opacity: 1 }
        },
        '@keyframes slidePrice': {
          '0%': { transform: 'translateX(-100px)', opacity: 0 },
          '10%': { opacity: 1 },
          '90%': { opacity: 1 },
          '100%': { transform: 'translateX(100vw)', opacity: 0 }
        },
        '@keyframes candlestick': {
          '0%': { scaleY: 0.8, opacity: 0.4 },
          '50%': { scaleY: 1.2, opacity: 0.8 },
          '100%': { scaleY: 0.8, opacity: 0.4 }
        }
      }}
    >
      {/* Símbolos de criptomoedas flutuantes */}
      {cryptoSymbols.map((symbol, index) => (
        <Box
          key={index}
          sx={{
            position: 'absolute',
            fontSize: '24px',
            color: 'rgba(0, 255, 100, 0.3)',
            animation: 'float 6s ease-in-out infinite',
            animationDelay: `${index * 1.2}s`,
            left: `${15 + index * 20}%`,
            top: `${20 + (index % 2) * 30}%`,
            pointerEvents: 'none',
            fontWeight: 'bold'
          }}
        >
          {symbol}
        </Box>
      ))}

      {/* Dados de mercado deslizantes */}
      {marketData.map((data, index) => (
        <Box
          key={index}
          sx={{
            position: 'absolute',
            top: `${10 + index * 12}%`,
            left: 0,
            fontSize: '14px',
            color: data.includes('+') ? 'rgba(0, 255, 100, 0.6)' : data.includes('-') ? 'rgba(255, 100, 100, 0.6)' : 'rgba(255, 255, 255, 0.4)',
            animation: 'slidePrice 8s linear infinite',
            animationDelay: `${index * 1.5}s`,
            pointerEvents: 'none',
            fontFamily: 'monospace',
            fontWeight: 'bold'
          }}
        >
          {data}
        </Box>
      ))}

      {/* Gráficos de candlestick simulados */}
      {Array.from({ length: 15 }).map((_, index) => (
        <Box
          key={`candle-${index}`}
          sx={{
            position: 'absolute',
            bottom: '10%',
            left: `${5 + index * 6}%`,
            width: '3px',
            height: `${20 + Math.random() * 40}px`,
            backgroundColor: Math.random() > 0.5 ? 'rgba(0, 255, 100, 0.3)' : 'rgba(255, 100, 100, 0.3)',
            animation: 'candlestick 3s ease-in-out infinite',
            animationDelay: `${index * 0.2}s`,
            pointerEvents: 'none',
            '&::before': {
              content: '""',
              position: 'absolute',
              top: '-10px',
              left: '50%',
              transform: 'translateX(-50%)',
              width: '1px',
              height: '10px',
              backgroundColor: 'inherit'
            },
            '&::after': {
              content: '""',
              position: 'absolute',
              bottom: '-10px',
              left: '50%',
              transform: 'translateX(-50%)',
              width: '1px',
              height: '10px',
              backgroundColor: 'inherit'
            }
          }}
        />
      ))}

      {/* Linhas de tendência */}
      <Box
        sx={{
          position: 'absolute',
          top: '30%',
          left: '10%',
          right: '10%',
          height: '2px',
          background: 'linear-gradient(90deg, transparent, rgba(0, 255, 100, 0.4), transparent)',
          animation: 'slidePrice 12s linear infinite',
          pointerEvents: 'none'
        }}
      />
      <Box
        sx={{
          position: 'absolute',
          top: '70%',
          left: '10%',
          right: '10%',
          height: '2px',
          background: 'linear-gradient(90deg, transparent, rgba(255, 100, 100, 0.4), transparent)',
          animation: 'slidePrice 15s linear infinite reverse',
          pointerEvents: 'none'
        }}
      />

      {/* Números de mercado flutuantes */}
      {Array.from({ length: 8 }).map((_, index) => (
        <Box
          key={`number-${index}`}
          sx={{
            position: 'absolute',
            fontSize: '12px',
            color: 'rgba(255, 255, 255, 0.2)',
            animation: 'float 8s ease-in-out infinite',
            animationDelay: `${index * 1}s`,
            left: `${Math.random() * 80 + 10}%`,
            top: `${Math.random() * 80 + 10}%`,
            pointerEvents: 'none',
            fontFamily: 'monospace'
          }}
        >
          {(Math.random() * 10000).toFixed(2)}
        </Box>
      ))}

      {/* Overlay escuro */}
      <Box
        sx={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: '100%',
          height: '100%',
          backgroundColor: 'rgba(0, 0, 0, 0.6)',
          zIndex: 1
        }}
      />

      <Container component="main" maxWidth="xs" sx={{ zIndex: 2, position: 'relative' }}>
        <Paper
          elevation={24}
          sx={{
            padding: 4,
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            backgroundColor: 'rgba(0, 0, 0, 0.85)',
            backdropFilter: 'blur(10px)',
            border: '1px solid rgba(0, 255, 100, 0.2)',
            borderRadius: 2,
            boxShadow: '0 8px 32px rgba(0, 255, 100, 0.1)'
          }}
        >
          <Typography
            variant="h4"
            component="h1"
            gutterBottom
            sx={{
              color: '#C0C0C0',
              fontWeight: 'bold',
              textAlign: 'center',
              mb: 3,
              textShadow: '0 0 10px rgba(0, 255, 100, 0.3)'
            }}
          >
            Nautilus Automação
          </Typography>

          {error && (
            <Alert severity="error" sx={{ width: '100%', mb: 2 }}>
              {error}
            </Alert>
          )}

          <Box component="form" onSubmit={handleSubmit} sx={{ width: '100%' }}>
            <TextField
              margin="normal"
              required
              fullWidth
              id="email"
              label="Email"
              name="email"
              type="email"
              autoComplete="email"
              autoFocus
              value={formData.email}
              onChange={handleChange}
              disabled={loading}
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Email sx={{ color: '#C0C0C0' }} />
                  </InputAdornment>
                ),
                style: { color: '#C0C0C0' }
              }}
              InputLabelProps={{
                style: { color: '#C0C0C0' }
              }}
              sx={{
                '& .MuiOutlinedInput-root': {
                  '& fieldset': {
                    borderColor: 'rgba(0, 255, 100, 0.3)'
                  },
                  '&:hover fieldset': {
                    borderColor: 'rgba(0, 255, 100, 0.5)'
                  },
                  '&.Mui-focused fieldset': {
                    borderColor: 'rgba(0, 255, 100, 0.7)'
                  }
                }
              }}
            />

            <TextField
              margin="normal"
              required
              fullWidth
              name="password"
              label="Senha"
              type={showPassword ? 'text' : 'password'}
              id="password"
              autoComplete="current-password"
              value={formData.password}
              onChange={handleChange}
              disabled={loading}
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Lock sx={{ color: '#C0C0C0' }} />
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton
                      aria-label="toggle password visibility"
                      onClick={togglePasswordVisibility}
                      edge="end"
                      sx={{ color: '#C0C0C0' }}
                    >
                      {showPassword ? <VisibilityOff /> : <Visibility />}
                    </IconButton>
                  </InputAdornment>
                ),
                style: { color: '#C0C0C0' }
              }}
              InputLabelProps={{
                style: { color: '#C0C0C0' }
              }}
              sx={{
                '& .MuiOutlinedInput-root': {
                  '& fieldset': {
                    borderColor: 'rgba(0, 255, 100, 0.3)'
                  },
                  '&:hover fieldset': {
                    borderColor: 'rgba(0, 255, 100, 0.5)'
                  },
                  '&.Mui-focused fieldset': {
                    borderColor: 'rgba(0, 255, 100, 0.7)'
                  }
                }
              }}
            />

            <Button
              type="submit"
              fullWidth
              variant="contained"
              disabled={loading}
              sx={{
                mt: 3,
                mb: 2,
                backgroundColor: 'rgba(0, 0, 0, 0.8)',
                color: '#C0C0C0',
                border: '1px solid rgba(0, 255, 100, 0.3)',
                '&:hover': {
                  backgroundColor: 'rgba(0, 255, 100, 0.1)',
                  borderColor: 'rgba(0, 255, 100, 0.5)',
                  boxShadow: '0 0 20px rgba(0, 255, 100, 0.3)'
                },
                '&:disabled': {
                  backgroundColor: 'rgba(0, 0, 0, 0.6)',
                  color: 'rgba(192, 192, 192, 0.5)'
                }
              }}
            >
              {loading ? <CircularProgress size={24} sx={{ color: '#C0C0C0' }} /> : 'Acessar'}
            </Button>

            <Box sx={{ mt: 2, textAlign: 'center' }}>
              <Typography variant="body2" sx={{ color: '#C0C0C0', mb: 2 }}>
                Não tem uma conta?
              </Typography>

              {/* Botões de Assinatura e Renovação */}
              <Box sx={{ mb: 3 }}>
                <Typography variant="subtitle2" sx={{ color: 'rgba(0, 255, 100, 0.8)', mb: 1, fontWeight: 'bold' }}>
                  🎯 Assinatura & Renovação
                </Typography>
                <Button
                  component="a"
                  href="https://pay.hub.la/tmF5YtOlGb1GDVFSam7S"
                  target="_blank"
                  rel="noopener noreferrer"
                  fullWidth
                  variant="outlined"
                  sx={{
                    mb: 1,
                    py: 1.2,
                    backgroundColor: 'rgba(0, 255, 100, 0.1)',
                    borderColor: 'rgba(0, 255, 100, 0.5)',
                    color: 'rgba(0, 255, 100, 0.9)',
                    fontWeight: 'bold',
                    '&:hover': {
                      backgroundColor: 'rgba(0, 255, 100, 0.2)',
                      borderColor: 'rgba(0, 255, 100, 0.8)',
                      boxShadow: '0 0 15px rgba(0, 255, 100, 0.3)'
                    }
                  }}
                >
                  🚀 Assinar Nautilus (R$ 299,99/mês)
                </Button>
              </Box>

              {/* Botões de Recarga */}
              <Box sx={{ mb: 3 }}>
                <Typography variant="subtitle2" sx={{ color: 'rgba(0, 255, 100, 0.8)', mb: 1, fontWeight: 'bold' }}>
                  💰 Recarregar Conta
                </Typography>
                <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
                  <Button
                    component="a"
                    href="https://pay.hub.la/ekfJp2uXQ0S5ZBb65Otb"
                    target="_blank"
                    rel="noopener noreferrer"
                    size="small"
                    variant="outlined"
                    sx={{
                      backgroundColor: 'rgba(0, 0, 0, 0.3)',
                      borderColor: 'rgba(192, 192, 192, 0.3)',
                      color: '#C0C0C0',
                      '&:hover': {
                        backgroundColor: 'rgba(192, 192, 192, 0.1)',
                        borderColor: 'rgba(192, 192, 192, 0.5)'
                      }
                    }}
                  >
                    R$ 9,00 (Teste)
                  </Button>
                  <Box sx={{ display: 'flex', gap: 1 }}>
                    <Button
                      component="a"
                      href="https://pay.hub.la/MdORdaFcTzWvhT9IkZHP"
                      target="_blank"
                      rel="noopener noreferrer"
                      size="small"
                      variant="outlined"
                      sx={{
                        flex: 1,
                        backgroundColor: 'rgba(0, 0, 0, 0.3)',
                        borderColor: 'rgba(192, 192, 192, 0.3)',
                        color: '#C0C0C0',
                        '&:hover': {
                          backgroundColor: 'rgba(192, 192, 192, 0.1)',
                          borderColor: 'rgba(192, 192, 192, 0.5)'
                        }
                      }}
                    >
                      R$ 50
                    </Button>
                    <Button
                      component="a"
                      href="https://pay.hub.la/mFfwQbUAqILTw8bfDXjo"
                      target="_blank"
                      rel="noopener noreferrer"
                      size="small"
                      variant="outlined"
                      sx={{
                        flex: 1,
                        backgroundColor: 'rgba(0, 0, 0, 0.3)',
                        borderColor: 'rgba(192, 192, 192, 0.3)',
                        color: '#C0C0C0',
                        '&:hover': {
                          backgroundColor: 'rgba(192, 192, 192, 0.1)',
                          borderColor: 'rgba(192, 192, 192, 0.5)'
                        }
                      }}
                    >
                      R$ 100
                    </Button>
                  </Box>
                  <Box sx={{ display: 'flex', gap: 1 }}>
                    <Button
                      component="a"
                      href="https://pay.hub.la/EVrxnuDyf4JeB0uIYaFC"
                      target="_blank"
                      rel="noopener noreferrer"
                      size="small"
                      variant="outlined"
                      sx={{
                        flex: 1,
                        backgroundColor: 'rgba(0, 0, 0, 0.3)',
                        borderColor: 'rgba(192, 192, 192, 0.3)',
                        color: '#C0C0C0',
                        '&:hover': {
                          backgroundColor: 'rgba(192, 192, 192, 0.1)',
                          borderColor: 'rgba(192, 192, 192, 0.5)'
                        }
                      }}
                    >
                      R$ 200
                    </Button>
                    <Button
                      component="a"
                      href="https://pay.hub.la/LmFhy6R6HP3fjoJxZe5z"
                      target="_blank"
                      rel="noopener noreferrer"
                      size="small"
                      variant="outlined"
                      sx={{
                        flex: 1,
                        backgroundColor: 'rgba(0, 0, 0, 0.3)',
                        borderColor: 'rgba(192, 192, 192, 0.3)',
                        color: '#C0C0C0',
                        '&:hover': {
                          backgroundColor: 'rgba(192, 192, 192, 0.1)',
                          borderColor: 'rgba(192, 192, 192, 0.5)'
                        }
                      }}
                    >
                      R$ 500
                    </Button>
                  </Box>
                </Box>
              </Box>

              {/* Código de Convite */}
              <Typography variant="body2" sx={{ color: '#C0C0C0' }}>
                Ou{' '}
                <Link
                  component={RouterLink}
                  to="/register"
                  sx={{ 
                    color: 'rgba(0, 255, 100, 0.8)', 
                    textDecoration: 'underline',
                    '&:hover': {
                      color: 'rgba(0, 255, 100, 1)'
                    }
                  }}
                >
                  🔑 Registrar com Código de Convite
                </Link>
              </Typography>
            </Box>

            <Box
              sx={{
                display: 'flex',
                justifyContent: 'center',
                gap: 2,
                mt: 3
              }}
            >
              <IconButton
                component="a"
                href="https://www.instagram.com/bigwhale.oficial/"
                target="_blank"
                rel="noopener noreferrer"
                sx={{ 
                  color: '#C0C0C0',
                  '&:hover': {
                    color: 'rgba(0, 255, 100, 0.8)'
                  }
                }}
              >
                <Instagram />
              </IconButton>
              <IconButton
                component="a"
                href="https://www.youtube.com/@BigWhaleOficial"
                target="_blank"
                rel="noopener noreferrer"
                sx={{ 
                  color: '#C0C0C0',
                  '&:hover': {
                    color: 'rgba(0, 255, 100, 0.8)'
                  }
                }}
              >
                <YouTube />
              </IconButton>
              <IconButton
                component="a"
                href="https://t.me/+VTVGAGhccP81MWVh"
                target="_blank"
                rel="noopener noreferrer"
                sx={{ 
                  color: '#C0C0C0',
                  '&:hover': {
                    color: 'rgba(0, 255, 100, 0.8)'
                  }
                }}
              >
                <TelegramIcon />
              </IconButton>
            </Box>
          </Box>
        </Paper>
      </Container>
    </Box>
  );
};

export default Login;
